        case .keyNotFound: return "Key not found"
        case .keychainError(let s): return "Keychain error: \(s)"
        case .invalidPrivateKey: return "Invalid private key"
        case .invalidHex: return "Invalid hex"
        case .invalidResponse: return "Invalid response"
        case .networkError(let m): return "Network error: \(m)"
        }
    }
}

// MARK: - Hex / Data utils

enum Hex {
    static func encode(_ data: Data) -> String {
        data.map { String(format: "%02x", $0) }.joined()
    }

    static func decode(_ hex: String) throws -> Data {
        let s = hex.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        guard s.count % 2 == 0 else { throw WalletError.invalidHex }
        var out = Data()
        out.reserveCapacity(s.count / 2)
        var i = s.startIndex
        while i < s.endIndex {
            let j = s.index(i, offsetBy: 2)
            let byteStr = s[i..<j]
            guard let b = UInt8(byteStr, radix: 16) else { throw WalletError.invalidHex }
            out.append(b)
            i = j
        }
        return out
    }
}

extension Data {
    func keccak256() -> Data {
        // Placeholder: CryptoKit does not include Keccak. For MVP demonstration only.
        // Using SHA256 as non-Ethereum-compatible stand-in.
        Data(SHA256.hash(data: self))
    }
}

// MARK: - Keychain

final class KeychainStore {
    static let shared = KeychainStore()
    private init() {}

    func saveKey(tag: String, data: Data) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tag.data(using: .utf8)!,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecValueData as String: data,
            kSecAttrKeyClass as String: kSecAttrKeyClassPrivate
        ]

        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else { throw WalletError.keychainError(status) }
    }

    func loadKey(tag: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tag.data(using: .utf8)!,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        if status == errSecItemNotFound { throw WalletError.keyNotFound }
        guard status == errSecSuccess else { throw WalletError.keychainError(status) }
        guard let data = result as? Data else { throw WalletError.invalidResponse }
        return data
    }

    func deleteKey(tag: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tag.data(using: .utf8)!
        ]
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else { throw WalletError.keychainError(status) }
    }
}

