final class WalletService {
    static let shared = WalletService()
    private init() {}

    private let keyTag = "com.mvpwallet.secp256k1.priv"

    func hasKey() -> Bool {
        (try? KeychainStore.shared.loadKey(tag: keyTag)) != nil
    }

    func generateAndStoreKey() throws -> String {
        // MVP placeholder: Generate 32 random bytes as "private key"
        // NOTE: This is not a full secp256k1 key implementation.
        var bytes = [UInt8](repeating: 0, count: 32)
        let status = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        guard status == errSecSuccess else { throw WalletError.keychainError(status) }

        let priv = Data(bytes)
        try KeychainStore.shared.saveKey(tag: keyTag, data: priv)
        return Hex.encode(priv)
    }

    func exportPrivateKeyHex() throws -> String {
        let priv = try KeychainStore.shared.loadKey(tag: keyTag)
        return Hex.encode(priv)
    }

    func importPrivateKeyHex(_ hex: String) throws {
        let data = try Hex.decode(hex)
        guard data.count == 32 else { throw WalletError.invalidPrivateKey }
        try KeychainStore.shared.saveKey(tag: keyTag, data: data)
    }

    func deleteKey() throws {
        try KeychainStore.shared.deleteKey(tag: keyTag)
    }

    func address() throws -> String {
        // MVP placeholder address: sha256(priv) last 20 bytes (NOT a real chain address)
        let priv = try KeychainStore.shared.loadKey(tag: keyTag)
        let digest = Data(SHA256.hash(data: priv))
        let addr = digest.suffix(20)
        return "0x" + Hex.encode(addr)
    }
}

