final class TransactionSigner {
    static let shared = TransactionSigner()
    private init() {}

    func sign(transaction: Transaction) throws -> SignedTransaction {
        let priv = try KeychainStore.shared.loadKey(tag: "com.mvpwallet.secp256k1.priv")

        // MVP placeholder signature: HMAC-SHA256(priv, txJSON)
        let json = try JSONEncoder().encode(transaction)
        let key = SymmetricKey(data: priv)
        let mac = HMAC<SHA256>.authenticationCode(for: json, using: key)
        let sig = Data(mac)

        // "raw" is txJSON + sig, base64
        var rawPack = Data()
        rawPack.append(json)
        rawPack.append(sig)

        let raw = rawPack.base64EncodedString()
        let txHash = Hex.encode((json + sig).keccak256())
        return SignedTransaction(raw: raw, txHash: "0x" + txHash)
    }
}

private func + (lhs: Data, rhs: Data) -> Data {
    var d = Data()
    d.reserveCapacity(lhs.count + rhs.count)
    d.append(lhs)
    d.append(rhs)
    return d
}

// MARK: - Blockchain Communication (JSON-RPC minimal)

final class JSONRPCClient {
    let endpoint: URL
    private let session: URLSession

    init(endpoint: URL, session: URLSession = .shared) {
        self.endpoint = endpoint
        self.session = session
    }

    struct RPCRequest: Encodable {
        let jsonrpc: String = "2.0"
        let id: Int
        let method: String
        let params: [EncodableValue]
    }

    struct RPCResponse<T: Decodable>: Decodable {
        let jsonrpc: String?
        let id: Int?
        let result: T?
        let error: RPCError?
    }

    struct RPCError: Decodable, Error {
        let code: Int
        let message: String
    }

    enum EncodableValue: Encodable {
        case string(String)
        case int(Int)
        case uint64(UInt64)
        case object([String: EncodableValue])
        case array([EncodableValue])
        case null

        func encode(to encoder: Encoder) throws {
            var container = encoder.singleValueContainer()
            switch self {
            case .string(let s): try container.encode(s)
            case .int(let i): try container.encode(i)
            case .uint64(let u): try container.encode(u)
            case .object(let o): try container.encode(o)
            case .array(let a): try container.encode(a)
            case .null: try container.encodeNil()
            }
        }
    }

    func call<T: Decodable>(_ method: String, _ params: [EncodableValue], response: T.Type) async throws -> T {
        let req = RPCRequest(id: Int.random(in: 1...Int.max), method: method, params: params)
        let body = try JSONEncoder().encode(req)

        var urlReq = URLRequest(url: endpoint)
        urlReq.httpMethod = "POST"
        urlReq.httpBody = body
        urlReq.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let (data, resp) = try await session.data(for: urlReq)
        guard let http = resp as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw WalletError.networkError("HTTP error")
        }

        let decoded = try JSONDecoder().decode(RPCResponse<T>.self, from: data)
        if let e = decoded.error { throw WalletError.networkError("\(e.code): \(e.message)") }
        guard let result = decoded.result else { throw WalletError.invalidResponse }
        return result
    }
}

final class BlockchainService {
