    private init() {
        client = JSONRPCClient(endpoint: URL(string: "https://cloudflare-eth.com")!)
    }

    func setEndpoint(_ urlString: String) {
        if let url = URL(string: urlString) {
            client = JSONRPCClient(endpoint: url)
        }
    }

    func ethGetBalance(address: String) async throws -> String {
        struct Balance: Decodable {}
        let res: String = try await client.call("eth_getBalance", [.string(address), .string("latest")], response: String.self)
        return res
    }

    func ethGetTransactionCount(address: String) async throws -> String {
        let res: String = try await client.call("eth_getTransactionCount", [.string(address), .string("latest")], response: String.self)
        return res
