        cfg.cornerStyle = .medium
        let b = UIButton(configuration: cfg)
        b.addAction(UIAction { _ in action() }, for: .touchUpInside)
        return b
    }

    @MainActor
    private func appendStatus(_ line: String) {
        let ts = ISO8601DateFormatter().string(from: Date())
        let newLine = "[\(ts)] \(line)\n"
        statusText.text = (statusText.text ?? "") + newLine
        let range = NSRange(location: (statusText.text as NSString).length - 1, length: 1)
        statusText.scrollRangeToVisible(range)
    }

    private func refreshAll() async {
        do {
            if WalletService.shared.hasKey() {
                let addr = try WalletService.shared.address()
                await MainActor.run {
                    addressLabel.text = "Address (MVP placeholder):\n\(addr)"
                }

                do {
                    let bal = try await BlockchainService.shared.ethGetBalance(address: addr)
                    await MainActor.run { balanceLabel.text = "Balance (RPC):\n\(bal)" }
                } catch {
                    await MainActor.run { balanceLabel.text = "Balance (RPC):\nError: \(error.localizedDescription)" }
                }

                do {
                    let nonce = try await BlockchainService.shared.ethGetTransactionCount(address: addr)
                    await MainActor.run { nonceLabel.text = "Nonce (RPC):\n\(nonce)" }
                } catch {
                    await MainActor.run { nonceLabel.text = "Nonce (RPC):\nError: \(error.localizedDescription)" }
                }
            } else {
                await MainActor.run {
                    addressLabel.text = "Address:\n(Generate or import a key)"
                    balanceLabel.text = "Balance:\n-"
                    nonceLabel.text = "Nonce:\n-"
                }
            }
        } catch {
            await appendStatus("Error: \(error.localizedDescription)")
        }
    }

    private func signOnly() async {
        do {
            guard WalletService.shared.hasKey() else { throw WalletError.keyNotFound }
            let addr = try WalletService.shared.address()
            let nonceHex = try await BlockchainService.shared.ethGetTransactionCount(address: addr)
            let nonce = UInt64(nonceHex.replacingOccurrences(of: "0x", with: ""), radix: 16) ?? 0

            let to = (toField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let value = (valueField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let chainId = Int((chainIdField.text ?? "1").trimmingCharacters(in: .whitespacesAndNewlines)) ?? 1
            let data = (dataField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let tx = Transaction(to: to, value: value, nonce: nonce, chainId: chainId, data: data.isEmpty ? nil : data)

            let signed = try TransactionSigner.shared.sign(transaction: tx)
            await appendStatus("Signed tx hash (MVP): \(signed.txHash)")
            await appendStatus("Raw (base64, MVP): \(signed.raw)")
        } catch {
            await appendStatus("Error: \(error.localizedDescription)")
        }
    }

    private func signAndSend() async {
        do {
            guard WalletService.shared.hasKey() else { throw WalletError.keyNotFound }
            let addr = try WalletService.shared.address()
            let nonceHex = try await BlockchainService.shared.ethGetTransactionCount(address: addr)
            let nonce = UInt64(nonceHex.replacingOccurrences(of: "0x", with: ""), radix: 16) ?? 0

            let to = (toField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let value = (valueField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let chainId = Int((chainIdField.text ?? "1").trimmingCharacters(in: .whitespacesAndNewlines)) ?? 1
            let data = (dataField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let tx = Transaction(to: to, value: value, nonce: nonce, chainId: chainId, data: data.isEmpty ? nil : data)

            let signed = try TransactionSigner.shared.sign(transaction: tx)
            let rpcTxHash = try await BlockchainService.shared.ethSendRawTransaction(raw: signed.raw)
            await appendStatus("RPC send result: \(rpcTxHash)")
        } catch {
            await appendStatus("Error: \(error.localizedDescription)")
        }
    }
